func TestEnumKeyType(t *testing.T) {
	t.Run("NewFromString_name", func(t *testing.T) {
		t.Parallel()
		val, err := NewKeyTypeFromString("name")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, KeyType("name"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_value", func(t *testing.T) {
		t.Parallel()
		val, err := NewKeyTypeFromString("value")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, KeyType("value"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewKeyTypeFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewKeyTypeFromString("name")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

func TestExtraPropertiesConvertToken(t *testing.T) {
	t.Run("GetExtraProperties", func(t *testing.T) {
		t.Parallel()
		obj := &ConvertToken{}
		// Should not panic when calling GetExtraProperties()
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("GetExtraProperties() panicked: %v", r)
			}
		}()
		extraProps := obj.GetExtraProperties()
		// Result can be nil or an empty/non-empty map
		_ = extraProps
	})

	t.Run("GetExtraProperties_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *ConvertToken
		extraProps := obj.GetExtraProperties()
		assert.Nil(t, extraProps, "nil receiver should return nil without panicking")
	})
}

